        Map<String, String> map = xsbDataParser.parseXsbDataToMap(xsbDataString);
        map.replaceAll((k, v) -> null);
        XsbDataJsonRecord xsbData =  new XsbDataJsonRecord(map, nonTAACountryCodes);
